import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { FiSettings, FiUser, FiLock, FiBell, FiMoon, FiSun } from 'react-icons/fi';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

const Settings = () => {
  const { user } = useAuth();
  const [darkMode, setDarkMode] = useState(true);
  const [notifications, setNotifications] = useState({
    assignments: true,
    exams: true,
    grades: true,
    announcements: false,
  });
  const [profile, setProfile] = useState({ name: user?.name || '', email: user?.email || '' });

  const handleProfileSave = () => {
    toast.success('Profile updated successfully!');
  };

  const handlePasswordSave = () => {
    toast.success('Password changed successfully!');
  };

  const Section = ({ icon, title, children }) => (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      style={{
        background: 'var(--card-bg)',
        border: '1px solid var(--border)',
        borderRadius: '16px',
        padding: '24px',
        marginBottom: '20px',
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px' }}>
        <span style={{ color: '#667eea', fontSize: '1.1rem' }}>{icon}</span>
        <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: '600' }}>{title}</h3>
      </div>
      {children}
    </motion.div>
  );

  const inputStyle = {
    width: '100%', padding: '10px 14px',
    background: 'rgba(255,255,255,0.05)',
    border: '1px solid var(--border)',
    borderRadius: '10px', color: 'var(--text-primary)',
    fontSize: '0.9rem', marginBottom: '12px', boxSizing: 'border-box',
  };

  const Toggle = ({ checked, onChange }) => (
    <div
      onClick={() => onChange(!checked)}
      style={{
        width: '44px', height: '24px', borderRadius: '12px',
        background: checked ? '#667eea' : 'rgba(255,255,255,0.1)',
        cursor: 'pointer', position: 'relative', transition: 'background 0.3s',
        flexShrink: 0,
      }}
    >
      <div style={{
        position: 'absolute', top: '3px',
        left: checked ? '23px' : '3px',
        width: '18px', height: '18px', borderRadius: '50%',
        background: '#fff', transition: 'left 0.3s',
      }} />
    </div>
  );

  return (
    <div style={{ padding: '30px', maxWidth: '650px', margin: '0 auto' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
        <FiSettings size={24} color="#667eea" />
        <h1 style={{ fontSize: '1.8rem', fontWeight: '700', margin: 0 }}>Settings</h1>
      </div>
      <p style={{ color: 'var(--text-muted)', marginBottom: '30px' }}>
        Manage your account preferences
      </p>

      {/* Profile */}
      <Section icon={<FiUser />} title="Profile Information">
        <input style={inputStyle} value={profile.name}
          onChange={e => setProfile({ ...profile, name: e.target.value })}
          placeholder="Full Name" />
        <input style={inputStyle} value={profile.email}
          onChange={e => setProfile({ ...profile, email: e.target.value })}
          placeholder="Email" type="email" />
        <button onClick={handleProfileSave} style={{
          padding: '10px 24px', background: 'var(--gradient-primary)',
          border: 'none', borderRadius: '10px', color: '#fff',
          fontWeight: '600', cursor: 'pointer', fontSize: '0.9rem',
        }}>
          Save Changes
        </button>
      </Section>

      {/* Password */}
      <Section icon={<FiLock />} title="Change Password">
        <input style={inputStyle} type="password" placeholder="Current Password" />
        <input style={inputStyle} type="password" placeholder="New Password" />
        <input style={inputStyle} type="password" placeholder="Confirm New Password" />
        <button onClick={handlePasswordSave} style={{
          padding: '10px 24px', background: 'var(--gradient-primary)',
          border: 'none', borderRadius: '10px', color: '#fff',
          fontWeight: '600', cursor: 'pointer', fontSize: '0.9rem',
        }}>
          Update Password
        </button>
      </Section>

      {/* Notifications */}
      <Section icon={<FiBell />} title="Notification Preferences">
        {Object.entries(notifications).map(([key, val]) => (
          <div key={key} style={{
            display: 'flex', justifyContent: 'space-between',
            alignItems: 'center', marginBottom: '14px',
          }}>
            <span style={{ textTransform: 'capitalize', fontSize: '0.9rem' }}>
              {key} notifications
            </span>
            <Toggle checked={val} onChange={v => setNotifications({ ...notifications, [key]: v })} />
          </div>
        ))}
      </Section>

      {/* Appearance */}
      <Section icon={darkMode ? <FiMoon /> : <FiSun />} title="Appearance">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span style={{ fontSize: '0.9rem' }}>Dark Mode</span>
          <Toggle checked={darkMode} onChange={setDarkMode} />
        </div>
      </Section>
    </div>
  );
};

export default Settings;
